  "sql": "SELECT Artist.Name, COUNT(DISTINCT Track.GenreId) AS NumGenres FROM Artist JOIN Album ON Artist.ArtistId = Album.ArtistId JOIN Track ON Album.AlbumId = Track.AlbumId GROUP BY Artist.ArtistId HAVING COUNT(DISTINCT Track.GenreId) > 3",
  "rationale": "Joins Artist, Album, and Track to count distinct genres per artist, filtering for those with more than 3."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, m.FirstName || ' ' || m.LastName AS ManagerName FROM Employee e LEFT JOIN Employee m ON e.ReportsTo = m.EmployeeId",
  "rationale": "Uses a LEFT JOIN on the Employee table to itself to retrieve each employee alongside their manager's name, preserving employees without a manager as NULL."
}

{
  "sql": "SELECT DISTINCT Country FROM Customer UNION SELECT DISTINCT BillingCountry AS Country FROM Invoice ORDER BY Country",
  "rationale": "Unions distinct countries from Customer and BillingCountry from Invoice, then orders alphabetically."
}

{
  "sql": "SELECT AVG(track_count) FROM (SELECT COUNT(*) AS track_count FROM Track GROUP BY AlbumId)",
  "rationale": "This query first counts the tracks for each album, then calculates the average of those counts."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, COUNT(c.CustomerId) AS CustomerCount FROM Employee e LEFT JOIN Customer c ON e.EmployeeId = c.SupportRepId GROUP BY e.EmployeeId ORDER BY CustomerCount DESC, EmployeeName",
  "rationale": "Left join Employee to Customer on SupportRepId to include employees with zero customers, count customers per employee, and order by the count descending then by employee name."
}

{
  "sql": "SELECT g.Name AS GenreName, t.Name AS TrackName, t.Milliseconds FROM Track t JOIN Genre g ON t.GenreId = g.GenreId WHERE t.Milliseconds = (SELECT MAX(t2.Milliseconds) FROM Track t2 WHERE t2.GenreId = t.GenreId) ORDER BY g.Name",
  "rationale": "Finds the track with the maximum milliseconds per genre using a correlated subquery, then joins to Genre for the genre name and orders alphabetically by genre."
}

{
  "sql": "SELECT FirstName || ' ' || LastName AS Name, City, COUNT(InvoiceId) AS InvoiceCount FROM Customer JOIN Invoice ON Customer.CustomerId = Invoice.CustomerId WHERE City LIKE 'S%' GROUP BY Customer.CustomerId HAVING COUNT(InvoiceId) > 1 ORDER BY InvoiceCount DESC, Name",
  "rationale": "Filters customers by cities starting with 'S', groups by customer to count invoices, keeps those with more than 1, and orders by the count descending then by the concatenated customer name."
}

{
  "sql": "SELECT g.Name AS Genre, SUM(il.UnitPrice * il.Quantity) AS TotalSales FROM Genre g JOIN Track t ON g.GenreId = t.GenreId JOIN InvoiceLine il ON t.TrackId = il.TrackId GROUP BY g.Name ORDER BY TotalSales DESC LIMIT 5",
  "rationale": "Join Genre to Track to InvoiceLine, sum UnitPrice * Quantity per genre, order descending, and limit to 5."
}

{
  "sql": "SELECT Album.Title FROM Album JOIN Artist ON Album.ArtistId = Artist.ArtistId WHERE Artist.Name = 'AC/DC'",
  "rationale": "Join Album and Artist tables to filter by artist name and return album titles."
}

{
  "sql": "SELECT FirstName, LastName, Email FROM Customer WHERE Country = 'Brazil'",
  "rationale": "Retrieve first name, last name, and email for customers whose country is Brazil."
}

{
  "sql": "SELECT mt.Name FROM MediaType mt JOIN Track t ON mt.MediaTypeId = t.MediaTypeId GROUP BY mt.MediaTypeId, mt.Name ORDER BY COUNT(*) DESC LIMIT 1",
  "rationale": "Count tracks per media type, order by count descending, and limit to the top one to find the most popular media type."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName FROM Customer c JOIN Employee e ON c.SupportRepId = e.EmployeeId GROUP BY e.EmployeeId ORDER BY COUNT(*) DESC LIMIT 1",
  "rationale": "Count customers per support rep, order by count descending, and return the top employee's full name."
}

{
  "sql": "SELECT SUM(il.UnitPrice * il.Quantity) AS TotalRevenue FROM InvoiceLine il JOIN Invoice i ON il.InvoiceId = i.InvoiceId WHERE strftime('%Y', i.InvoiceDate) = '2021'",
  "rationale": "Sum the product of UnitPrice and Quantity from InvoiceLine for invoices dated in 2021."
}

{
  "sql": "SELECT BillingCountry, AVG(Total) AS AverageTotal FROM Invoice GROUP BY BillingCountry ORDER BY AverageTotal DESC",
  "rationale": "Calculate the average of Total for each BillingCountry and order descending."
}

{
  "sql": "SELECT a.Name, COUNT(DISTINCT g.GenreId) AS num_genres FROM Artist a JOIN Album al ON a.ArtistId = al.ArtistId JOIN Track t ON al.AlbumId = t.AlbumId JOIN Genre g ON t.GenreId = g.GenreId GROUP BY a.ArtistId, a.Name HAVING COUNT(DISTINCT g.GenreId) > 3",
  "rationale": "Join artist to albums to tracks to genres, count distinct genres per artist, and keep only those with more than 3 distinct genres."
}

{
  "sql": "SELECT COUNT(*) FROM Track WHERE Milliseconds > (SELECT AVG(Milliseconds) FROM Track)",
  "rationale": "Count tracks whose length in milliseconds exceeds the average track length."
}

{
  "sql": "SELECT CASE WHEN Milliseconds < 180000 THEN 'short' WHEN Milliseconds <= 300000 THEN 'medium' ELSE 'long' END AS bucket, COUNT(*) AS count FROM Track GROUP BY bucket ORDER BY bucket",
  "rationale": "Categorize tracks by length in milliseconds and count per category."
}

{
  "sql": "SELECT FirstName || ' ' || LastName AS FullName, Title FROM Employee WHERE ReportsTo IS NULL",
  "rationale": "Employees who do not report to a manager have a NULL ReportsTo value, so we filter for those and concatenate their first and last names."
}

{
  "sql": "SELECT COUNT(*) AS invoice_count FROM Invoice WHERE InvoiceDate >= '2022-01-01' AND InvoiceDate < '2022-04-01'",
  "rationale": "Counts all invoices with InvoiceDate in the first quarter of 2022 (January 1 to March 31 inclusive)."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, m.FirstName || ' ' || m.LastName AS ManagerName FROM Employee e LEFT JOIN Employee m ON e.ReportsTo = m.EmployeeId",
  "rationale": "Self-join Employee on ReportsTo to get manager details, using LEFT JOIN to include employees with no manager (NULL manager name)."
}

{
  "sql": "SELECT COUNT(DISTINCT Country) AS distinct_countries FROM Customer",
  "rationale": "Counts the number of unique country values in the Customer table."
}

{
  "sql": "SELECT Country FROM Customer UNION SELECT BillingCountry FROM Invoice ORDER BY Country",
  "rationale": "Combine distinct countries from Customer and Invoice billing addresses, then sort alphabetically."
}

{
  "sql": "SELECT AVG(track_count) FROM (SELECT COUNT(t.TrackId) AS track_count FROM Album a LEFT JOIN Track t ON a.AlbumId = t.AlbumId GROUP BY a.AlbumId)",
  "rationale": "Calculate the average of track counts per album by left joining Album with Track to include albums with zero tracks."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, COUNT(c.CustomerId) AS CustomerCount FROM Employee e LEFT JOIN Customer c ON e.EmployeeId = c.SupportRepId GROUP BY e.EmployeeId, e.FirstName, e.LastName ORDER BY CustomerCount DESC, EmployeeName",
  "rationale": "Left join Employee to Customer on SupportRepId, count customers per employee, order by count descending then employee name."
}

{
  "sql": "SELECT COUNT(*) FROM Track WHERE LOWER(Name) LIKE '%love%'",
  "rationale": "Counts tracks whose name contains the substring 'love' after converting to lowercase for case-insensitive matching."
}

{
  "sql": "SELECT CASE WHEN Total < 5 THEN 'small' WHEN Total <= 10 THEN 'medium' ELSE 'large' END AS bucket, COUNT(*) AS count FROM Invoice GROUP BY bucket",
  "rationale": "Categorize each invoice by its Total into three buckets and count the number of invoices per bucket."
}

{
  "sql": "SELECT SUM(Total) AS total_revenue FROM Invoice WHERE InvoiceDate >= date((SELECT MAX(InvoiceDate) FROM Invoice), '-6 months')",
  "rationale": "Sum the Total column for invoices dated within the last 6 months relative to the most recent invoice date."
}

{
  "sql": "SELECT c.FirstName || ' ' || c.LastName AS Name, c.City, COUNT(i.InvoiceId) AS InvoiceCount FROM Customer c JOIN Invoice i ON c.CustomerId = i.CustomerId WHERE c.City LIKE 'S%' GROUP BY c.CustomerId HAVING COUNT(i.InvoiceId) > 1 ORDER BY InvoiceCount DESC, Name",
  "rationale": "List customers in cities starting with 'S' who have more than one invoice, showing their full name, city, and invoice count, ordered by count descending then name."
}
